use strict;
use warnings;

my %plugins;

sub load_plugins {
    my $dir = 'path/to/plugins';
    opendir(my $dh, $dir) or die "Cannot open directory '$dir': $!";
    while (my $file = readdir($dh)) {
        next if $file eq '.' || $file eq '..';
        push @{$plugins{$file}}, do {
            local $/;
            <"$dir/$file">
        };
    }
    closedir($dh);
}

sub run_plugin {
    my ($name) = @_;
    return if !exists $plugins{$name};
    eval($plugins[$name][0]);
}

load_plugins(); # load all plugins on startup

# Example usage:
run_plugin('example');